<template><div class="page-container"><el-card><template #header><span>订单利润</span><el-button size="small" type="primary" style="float:right" @click="handleRecalc">重算利润</el-button></template><el-form :inline="true"><el-form-item label="结算月份"><el-input v-model="f.settlement_month" placeholder="YYYY-MM" clearable style="width:120px"/></el-form-item><el-form-item label="搜索"><el-input v-model="f.search" placeholder="订单ID/MSKU" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="order_id" label="订单ID" width="150"/><el-table-column prop="msku" label="MSKU" width="100"/><el-table-column prop="sales_amount" label="销售额" width="100"/><el-table-column prop="purchase_cost" label="采购成本" width="100"/><el-table-column prop="shipping_cost" label="头程费用" width="100"/><el-table-column prop="platform_fee" label="平台费" width="80"/><el-table-column prop="fba_fee" label="FBA费用" width="80"/><el-table-column prop="advertising_fee" label="广告费" width="80"/><el-table-column prop="profit" label="利润" width="100"><template #default="{ row }"><span :style="{color:row.profit>0?'green':'red'}">{{ row.profit }}</span></template></el-table-column><el-table-column prop="profit_rate" label="利润率" width="80"/><el-table-column prop="settlement_month" label="结算月份" width="100"/></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { getOrderProfits } from '@/api/finance'
const f = reactive({ settlement_month: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await getOrderProfits({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
function handleRecalc() { /* recalc */ }
onMounted(load)
</script>
